import z from 'zod';

import { successResponse, outputAndExit, errorResponse } from '@/cli/output';

import { checkEndpoint } from '@/operations/check-endpoint';

import { getWalletOrExit } from '../lib/get-wallet-or-exit';

import type { Command } from '@/types';
import { cliRequestSchema } from '@/shared/request/schemas/cli';
import { RequestMethod } from '@/shared/request/types';

const SURFACE = 'cli:check';

export const checkCommand: Command<
  z.input<typeof cliRequestSchema>
> = async args => {
  const requestInput = cliRequestSchema
    .extend({
      method: z.enum(RequestMethod).optional(),
    })
    .safeParse(args);
  if (!requestInput.success) {
    return outputAndExit(
      errorResponse({
        code: 'INVALID_INPUT',
        message: requestInput.error.message,
        surface: SURFACE,
        cause: 'validation',
      }),
      args
    );
  }
  const wallets = await getWalletOrExit(args);

  const result = await checkEndpoint(SURFACE, requestInput.data, {
    wallets,
    flags: args,
  });

  if (!result.found) {
    return outputAndExit(
      successResponse({
        url: args.url,
        results: [],
        error: result.cause,
        message: result.message,
      }),
      args
    );
  }

  return outputAndExit(
    successResponse({ url: args.url, results: result.advisories }),
    args
  );
};
